import { QuoteCardSkeleton } from "@/components/ui/Skeleton";

export default function Loading() {
  return (
    <div className="max-w-4xl mx-auto px-4 py-8 sm:py-12">
      {/* Hero Section Skeleton */}
      <div className="text-center mb-12">
        <div className="h-12 w-64 bg-gray-200 dark:bg-gray-700 rounded-lg mx-auto mb-4 animate-pulse" />
        <div className="h-6 w-96 max-w-full bg-gray-200 dark:bg-gray-700 rounded mx-auto animate-pulse" />
      </div>

      {/* Main Quote Skeleton */}
      <section className="mb-12">
        <div className="flex items-center justify-between mb-6">
          <div className="h-6 w-40 bg-gray-200 dark:bg-gray-700 rounded animate-pulse" />
          <div className="h-10 w-28 bg-gray-200 dark:bg-gray-700 rounded-lg animate-pulse" />
        </div>
        <QuoteCardSkeleton />
      </section>

      {/* Suggestions Skeleton */}
      <section>
        <div className="h-6 w-48 bg-gray-200 dark:bg-gray-700 rounded mb-6 animate-pulse" />
        <div className="grid gap-6">
          <QuoteCardSkeleton />
          <QuoteCardSkeleton />
        </div>
      </section>
    </div>
  );
}
